					wall* w = &Walls[out[1]];
					out[2] = w->type;
					out[3] = w->state;
					out[4] = w->linked_wall;
					int child_segnum = seg->children[side];
					out[5] = child_segnum;
					segment* csegp = &Segments[child_segnum];
